from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    # Check if the file exists
    path_obj = Path(index_path)
    if not path_obj.exists():
        raise FileNotFoundError(f"Index metadata file not found at: {index_path}")

    # Initialize counters and storage
    total_passages = 0
    metadata_fields = set()
    # Structure: {field_name: {value: count}}
    field_value_counts = defaultdict(Counter)

    # Initialize the PassageManager
    # Assuming PassageManager is iterable and yields objects with a .metadata attribute
    try:
        pm = PassageManager(index_path)

        for passage in pm:
            total_passages += 1

            # Access metadata safely
            meta = getattr(passage, 'metadata', {})
            if not meta and isinstance(passage, dict):
                # Fallback if passage itself is the dict
                meta = passage

            for key, value in meta.items():
                metadata_fields.add(key)

                # Convert unhashable types (like lists/dicts) to string representation
                # to ensure they can be counted
                if isinstance(value, (list, dict, set)):
                    value = str(value)

                field_value_counts[key][value] += 1

    except Exception as e:
        # If the library raises a specific file not found error internally
        if "No such file" in str(e) or isinstance(e, FileNotFoundError):
            raise FileNotFoundError(f"Index metadata file not found at: {index_path}") from e
        raise e

    return {
        "total_passages": total_passages,
        "metadata_fields": list(metadata_fields),
        "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()}
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    # Check if the file exists
    path_obj = Path(index_path)
    if not path_obj.exists():
        raise FileNotFoundError(f"Index metadata file not found at: {index_path}")

    total_passages = 0
    passages_with_all_fields = 0
    field_occurrence_counts = Counter()

    try:
        pm = PassageManager(index_path)

        for passage in pm:
            total_passages += 1

            # Access metadata safely
            meta = getattr(passage, 'metadata', {})
            if not meta and isinstance(passage, dict):
                meta = passage

            # Check for presence of all required fields in this passage
            has_all_required = True

            for field in required_fields:
                if field in meta:
                    field_occurrence_counts[field] += 1
                else:
                    has_all_required = False

            if has_all_required:
                passages_with_all_fields += 1

    except Exception as e:
        if "No such file" in str(e) or isinstance(e, FileNotFoundError):
            raise FileNotFoundError(f"Index metadata file not found at: {index_path}") from e
        raise e

    # Calculate statistics
    if total_passages == 0:
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": required_fields
        }

    coverage_percentage = (passages_with_all_fields / total_passages) * 100.0

    field_coverage = {
        field: (field_occurrence_counts[field] / total_passages) * 100.0
        for field in required_fields
    }

    missing_fields = [
        field for field in required_fields 
        if field_occurrence_counts[field] == 0
    ]

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": {k: round(v, 2) for k, v in field_coverage.items()},
        "missing_fields": missing_fields
    }
